request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?name WHERE {
  ?pkg rdf:type vocab:package .
  ?pkg vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("TMT")) || CONTAINS(LCASE(STR(?name)), LCASE("Projet")) || CONTAINS(LCASE(STR(?name)), LCASE("Project")) || CONTAINS(LCASE(STR(?name)), LCASE("Work")) || CONTAINS(LCASE(STR(?name)), LCASE("Package")))
  FILTER NOT EXISTS { ?child vocab:Element_owner ?pkg . }
}
LIMIT 25
